import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getCarAdvice = async (carModel: string, problem: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Siz professional avtomobil ustasisiz (Million KM servisidan). Mijozning mashinasi: ${carModel}. Muammo: ${problem}. Mijozga qisqa, tushunarli va foydali maslahat bering (o'zbek tilida).`,
      config: {
        temperature: 0.7,
        topP: 0.95,
        maxOutputTokens: 250,
      }
    });
    return response.text || "Kechirasiz, hozircha maslahat bera olmayman.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Texnik nosozlik yuz berdi. Iltimos, keyinroq urinib ko'ring.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, Car, ServiceType } from './types';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import StatusChecker from './components/StatusChecker';
import BrandGrid from './components/BrandGrid';
import Cabinet from './components/Cabinet';
import Admin from './components/Admin';
import MobileService from './components/MobileService';
import AIConsultant from './components/AIConsultant';

type View = 'home' | 'cabinet' | 'admin' | 'express' | 'fuel';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  // Simplified session handling
  useEffect(() => {
    const savedUser = localStorage.getItem('million_km_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('million_km_user', JSON.stringify(user));
    setIsAuthModalOpen(false);
    showToast(`Xush kelibsiz, ${user.name}!`);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('million_km_user');
    setCurrentView('home');
    showToast("Tizimdan chiqdingiz.");
  };

  const renderView = () => {
    switch (currentView) {
      case 'cabinet':
        return currentUser ? <Cabinet user={currentUser} showToast={showToast} /> : <Hero onStart={() => setIsAuthModalOpen(true)} />;
      case 'admin':
        return currentUser?.isAdmin ? <Admin /> : <div className="p-20 text-center">Ruxsat yo'q</div>;
      case 'express':
      case 'fuel':
        return <MobileService type={currentView} user={currentUser} showToast={showToast} onOpenAuth={() => setIsAuthModalOpen(true)} />;
      default:
        return (
          <>
            <Hero onStart={() => document.getElementById('brands')?.scrollIntoView({ behavior: 'smooth' })} />
            <div id="status" className="max-w-7xl mx-auto px-4 py-12">
               <StatusChecker showToast={showToast} />
            </div>
            <div id="brands" className="max-w-7xl mx-auto px-4 py-20">
              <BrandGrid user={currentUser} showToast={showToast} onOpenAuth={() => setIsAuthModalOpen(true)} />
            </div>
            <AIConsultant />
          </>
        );
    }
  };

  return (
    <div className="min-h-screen pb-20">
      <Navbar 
        currentView={currentView} 
        setView={setCurrentView} 
        user={currentUser} 
        onLogout={handleLogout} 
        onLoginClick={() => setIsAuthModalOpen(true)} 
      />

      <main>
        {renderView()}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 py-12 mt-20">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="text-2xl font-bold mb-4 bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
            Million KM
          </div>
          <p className="text-gray-500 mb-8 max-w-md mx-auto">
            Dvigatel uchun yangi avlod ishonchi. O'zbekistondagi ilk premium avtoservis tarmog'i.
          </p>
          <div className="flex justify-center space-x-6 mb-8 text-gray-400">
            <a href="#" className="hover:text-blue-600 transition-colors"><i className="fab fa-instagram text-xl"></i></a>
            <a href="#" className="hover:text-blue-600 transition-colors"><i className="fab fa-telegram text-xl"></i></a>
            <a href="#" className="hover:text-blue-600 transition-colors"><i className="fab fa-youtube text-xl"></i></a>
          </div>
          <p className="text-xs text-gray-400">© 2024 Million KM Service. Barcha huquqlar himoyalangan.</p>
        </div>
      </footer>

      {/* Auth Modal Mockup */}
      {isAuthModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl relative animate-in fade-in zoom-in duration-200">
            <button onClick={() => setIsAuthModalOpen(false)} className="absolute top-6 right-6 text-gray-400 hover:text-gray-600">
              <i className="fas fa-times text-xl"></i>
            </button>
            <h2 className="text-2xl font-bold mb-6 text-center">Tizimga kirish</h2>
            <div className="space-y-4">
               <button 
                onClick={() => handleLogin({ uid: 'u1', name: 'Sherzod', email: 'sh@mail.uz', phone: '+998901234567', gender: 'male', isAdmin: true })}
                className="w-full bg-blue-600 text-white py-3 rounded-xl font-semibold hover:bg-blue-700 transition-all flex items-center justify-center"
               >
                 <i className="fas fa-user-shield mr-2"></i> Admin bo'lib kirish
               </button>
               <button 
                onClick={() => handleLogin({ uid: 'u2', name: 'Mijoz', email: 'mijoz@mail.uz', phone: '+998991234567', gender: 'male', isAdmin: false })}
                className="w-full border border-gray-200 py-3 rounded-xl font-semibold hover:bg-gray-50 transition-all flex items-center justify-center"
               >
                 <i className="fas fa-user mr-2"></i> Mijoz bo'lib kirish
               </button>
            </div>
            <p className="text-center text-sm text-gray-500 mt-6">
              Bu demo versiya uchun test loginlari hisoblanadi.
            </p>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className={`fixed bottom-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-xl flex items-center space-x-3 text-white animate-in slide-in-from-right duration-300 ${toast.type === 'success' ? 'bg-green-500' : 'bg-red-500'}`}>
          <i className={`fas ${toast.type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'}`}></i>
          <span className="font-medium">{toast.message}</span>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
