import React, { useState } from 'react';
import { User, Car, Order } from '../types';

interface CabinetProps {
  user: User;
  showToast: (msg: string, type: any) => void;
  onOrder: (order: Partial<Order>) => void;
}

const Cabinet: React.FC<CabinetProps> = ({ user, showToast, onOrder }) => {
  const [cars, setCars] = useState<Car[]>([
    { 
      id: 'c1', 
      userUid: user.uid, 
      brand: 'Chevrolet', 
      model: 'Cobalt', 
      year: 2022, 
      lastOilKm: 42000, 
      dailyKm: 45, 
      createdAt: new Date().toISOString() 
    }
  ]);

  const [isAddOpen, setIsAddOpen] = useState(false);
  const [newCar, setNewCar] = useState({ brand: '', model: '', year: '', lastOil: '', daily: '' });

  const addCar = () => {
    if (!newCar.brand || !newCar.model || !newCar.year || !newCar.lastOil) {
      showToast("Iltimos, barcha maydonlarni to'ldiring", 'error');
      return;
    }
    const car: Car = {
      id: Math.random().toString(36).substr(2, 9),
      userUid: user.uid,
      brand: newCar.brand,
      model: newCar.model,
      year: parseInt(newCar.year),
      lastOilKm: parseInt(newCar.lastOil),
      dailyKm: parseInt(newCar.daily) || 30,
      createdAt: new Date().toISOString()
    };
    setCars([...cars, car]);
    setIsAddOpen(false);
    setNewCar({ brand: '', model: '', year: '', lastOil: '', daily: '' });
    showToast("Mashina garajga qo'shildi!", 'success');
  };

  const requestService = (car: Car) => {
    onOrder({
      brand: car.brand,
      model: car.model,
      serviceType: 'Garage Service Request',
      note: `Garajdan so'rov: ${car.lastOilKm} km da oxirgi moy almashtirilgan.`
    });
  };

  return (
    <div className="max-w-7xl mx-auto px-4 pt-32 pb-20">
      <div className="bg-white rounded-[3rem] p-10 md:p-16 shadow-sm border border-gray-100 mb-12">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
          <div>
            <span className="text-blue-600 font-bold uppercase tracking-widest text-xs mb-2 block">Shaxsiy profil</span>
            <h1 className="text-5xl font-black text-slate-900 tracking-tight">Salom, {user.name}!</h1>
            <p className="text-slate-500 mt-2 text-lg">Sizning avtoparkingiz holati va xizmatlar tarixi.</p>
          </div>
          <button 
            onClick={() => setIsAddOpen(true)}
            className="group bg-blue-600 text-white px-10 py-5 rounded-[2rem] font-bold shadow-xl shadow-blue-200 hover:bg-slate-900 transition-all flex items-center active:scale-95"
          >
            <i className="fas fa-plus mr-3 group-hover:rotate-90 transition-transform"></i> 
            <span>Mashina qo'shish</span>
          </button>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-10">
        {cars.map(car => {
          const serviceInterval = 8000;
          const nextServiceKm = car.lastOilKm + serviceInterval;
          const drivenSinceLast = 1500; // Mock current distance
          const remainingKm = serviceInterval - drivenSinceLast;
          const progress = (drivenSinceLast / serviceInterval) * 100;
          const daysToService = Math.ceil(remainingKm / car.dailyKm);

          return (
            <div key={car.id} className="bg-white rounded-[3rem] overflow-hidden shadow-lg border border-gray-100 hover:shadow-2xl transition-all group">
              <div className="p-10">
                <div className="flex justify-between items-start mb-10">
                  <div className="flex items-center space-x-6">
                    <div className="w-20 h-20 bg-slate-900 rounded-[1.5rem] flex items-center justify-center text-white text-3xl group-hover:bg-blue-600 transition-colors duration-500">
                      <i className="fas fa-car-alt"></i>
                    </div>
                    <div>
                      <h3 className="text-3xl font-extrabold text-slate-900">{car.brand} {car.model}</h3>
                      <p className="text-slate-400 font-bold text-sm uppercase tracking-widest mt-1">{car.year}-yil • {car.lastOilKm.toLocaleString()} km</p>
                    </div>
                  </div>
                  <div className="px-5 py-2 bg-green-50 text-green-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-green-100">
                    Sog'lom Dvigatel
                  </div>
                </div>

                <div className="space-y-10">
                  <div>
                    <div className="flex justify-between items-end mb-4">
                      <div className="space-y-1">
                        <span className="text-xs text-slate-400 font-bold uppercase tracking-wider block">Keyingi servis holati</span>
                        <span className="text-2xl font-black text-slate-900">{remainingKm.toLocaleString()} km qoldi</span>
                      </div>
                      <span className="text-blue-600 font-black text-sm uppercase tracking-widest">~{daysToService} kun</span>
                    </div>
                    <div className="w-full h-4 bg-gray-100 rounded-full overflow-hidden p-1">
                      <div 
                        className={`h-full rounded-full transition-all duration-1000 ${progress > 80 ? 'bg-red-500' : 'bg-blue-600'}`} 
                        style={{ width: `${progress}%` }}
                      ></div>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-6">
                    <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                      <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-2">Servis chegarasi</div>
                      <div className="text-xl font-black text-slate-900">{nextServiceKm.toLocaleString()} km</div>
