                      <div className="text-xl font-black text-slate-900">{car.dailyKm} km/kun</div>
                    </div>
                  </div>
                </div>

                <div className="mt-12 flex space-x-4">
                   <button 
                    onClick={() => requestService(car)}
                    className="flex-1 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-blue-600 transition-all shadow-xl shadow-slate-100"
                   >
                     Servisga yozilish
                   </button>
                   <button className="w-16 h-16 bg-gray-50 text-slate-400 rounded-2xl flex items-center justify-center hover:bg-red-50 hover:text-red-500 transition-all">
                     <i className="fas fa-history text-lg"></i>
                   </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {isAddOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white rounded-[3rem] p-12 w-full max-w-xl shadow-2xl relative animate-in zoom-in duration-300">
              <button onClick={() => setIsAddOpen(false)} className="absolute top-10 right-10 text-gray-400 hover:text-slate-900">
                <i className="fas fa-times text-2xl"></i>
              </button>
              <h2 className="text-3xl font-black mb-10 text-slate-900">Yangi mashina qo'shish</h2>
              <div className="space-y-5">
                <div className="grid grid-cols-2 gap-5">
                  <input 
                    className="w-full px-6 py-5 bg-gray-50 border-none rounded-[1.5rem] focus:ring-2 focus:ring-blue-500 font-bold text-slate-900 transition-all" 
