                    placeholder="Model" 
                    value={newCar.model}
                    onChange={e => setNewCar({...newCar, model: e.target.value})}
                  />
                </div>
                <div className="grid grid-cols-2 gap-5">
                  <input 
                    type="number"
                    className="w-full px-6 py-5 bg-gray-50 border-none rounded-[1.5rem] focus:ring-2 focus:ring-blue-500 font-bold text-slate-900 transition-all" 
                    placeholder="Yili" 
                    value={newCar.year}
                    onChange={e => setNewCar({...newCar, year: e.target.value})}
