type View = 'home' | 'cabinet' | 'admin' | 'express' | 'fuel' | 'about' | 'locations';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('million_km_user');
    const savedOrders = localStorage.getItem('million_km_orders');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedOrders) setOrders(JSON.parse(savedOrders));
  }, []);

  const addOrder = async (orderData: Partial<Order>) => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      userName: orderData.userName || currentUser?.name || 'Mehmon',
      brand: orderData.brand || 'Nomaʼlum',
      model: orderData.model || 'Nomaʼlum',
      serviceType: orderData.serviceType || 'Servis',
      phone: orderData.phone || currentUser?.phone || '',
      note: orderData.note || '',
      timestamp: new Date().toLocaleString('uz-UZ'),
    };

    // Prepare Telegram Message
    const tgMessage = `
<b>🚀 Yangi Buyurtma!</b>
<b>Mijoz:</b> ${newOrder.userName}
<b>Telefon:</b> ${newOrder.phone}
<b>Mashina:</b> ${newOrder.brand} ${newOrder.model}
<b>Xizmat:</b> ${newOrder.serviceType}
<b>Izoh:</b> ${newOrder.note}
<b>Vaqt:</b> ${newOrder.timestamp}
    `;

    await sendTelegramNotification(tgMessage);

    const updated = [newOrder, ...orders];
    setOrders(updated);
    localStorage.setItem('million_km_orders', JSON.stringify(updated));
    showToast("Buyurtmangiz guruhga yuborildi!", "success");
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('million_km_user', JSON.stringify(user));
    setIsAuthModalOpen(false);
    showToast(`Xush kelibsiz, ${user.name}!`);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('million_km_user');
    setCurrentView('home');
    showToast("Tizimdan chiqdingiz.");
  };

  const renderView = () => {
    switch (currentView) {
      case 'cabinet':
        return currentUser ? <Cabinet user={currentUser} showToast={showToast} onOrder={addOrder} /> : <Hero onStart={() => setIsAuthModalOpen(true)} />;
      case 'admin':
        return currentUser?.isAdmin ? <Admin orders={orders} /> : <div className="p-20 text-center font-bold text-red-500">Ruxsat yo'q</div>;
      case 'express':
      case 'fuel':
        return <MobileService type={currentView} user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} />;
      case 'about':
        return <AboutUs />;
      case 'locations':
        return <NearestLocations />;
      default:
        return (
          <div className="animate-in fade-in duration-700">
            <Hero onStart={() => document.getElementById('brands')?.scrollIntoView({ behavior: 'smooth' })} />
            <div id="status" className="max-w-7xl mx-auto px-4 py-16">
               <StatusChecker showToast={showToast} />
            </div>
            <div id="brands" className="max-w-7xl mx-auto px-4 py-16">
              <BrandGrid user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} />
            </div>
            <AIConsultant />
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-blue-100 selection:text-blue-900">
      <Navbar 
        currentView={currentView} 
        setView={setCurrentView} 
        user={currentUser} 
        onLogout={handleLogout} 
        onLoginClick={() => setIsAuthModalOpen(true)} 
      />

      <main className="flex-grow pt-20">
        {renderView()}
      </main>

      <footer className="bg-white border-t border-slate-100 py-20 mt-20">
        <div className="max-w-7xl mx-auto px-6 text-center">
          <div className="text-2xl font-extrabold mb-6 tracking-tighter">Million KM</div>
          <p className="text-slate-500 max-w-md mx-auto leading-relaxed mb-8">
            Premium avtoservis tarmog'i. Barcha buyurtmalar real vaqtda Telegram orqali muvofiqlashtiriladi.
          </p>
          <div className="flex justify-center space-x-6">
            <button onClick={() => setCurrentView('about')} className="text-sm font-bold text-slate-400 hover:text-blue-600 transition-colors">Biz haqimizda</button>
            <button onClick={() => setCurrentView('locations')} className="text-sm font-bold text-slate-400 hover:text-blue-600 transition-colors">Manzillarimiz</button>
          </div>
          <p className="mt-12 text-[10px] text-slate-300 uppercase tracking-widest font-bold">© 2024 Million KM Service</p>
        </div>
      </footer>

      {isAuthModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-[2.5rem] p-10 w-full max-w-md shadow-2xl relative animate-in zoom-in fade-in duration-300">
            <button onClick={() => setIsAuthModalOpen(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors">
              <i className="fas fa-times text-xl"></i>
            </button>
            <h2 className="text-3xl font-extrabold text-slate-900 text-center mb-10 tracking-tight">Xush kelibsiz</h2>
            <div className="space-y-4">
               <button onClick={() => handleLogin({ uid: 'u1', name: 'Sherzod Admin', email: 'admin@million.uz', phone: '+998901234567', gender: 'male', isAdmin: true })} className="w-full bg-slate-900 text-white py-4.5 rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center"><i className="fas fa-user-shield mr-3 text-blue-400"></i> Admin</button>
               <button onClick={() => handleLogin({ uid: 'u2', name: 'Azizbek Mijoz', email: 'aziz@mail.uz', phone: '+998997771122', gender: 'male', isAdmin: false })} className="w-full border-2 border-slate-100 py-4.5 rounded-2xl font-bold text-slate-700 hover:bg-slate-50 transition-all flex items-center justify-center"><i className="fas fa-user mr-3 text-slate-400"></i> Mijoz</button>
            </div>
          </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 z-[110] px-8 py-4.5 rounded-2xl shadow-2xl flex items-center space-x-4 text-white animate-in slide-in-from-bottom-12 duration-500 ${toast.type === 'success' ? 'bg-slate-900' : 'bg-red-600'}`}>
          <i className={`fas ${toast.type === 'success' ? 'fa-check' : 'fa-exclamation-triangle'}`}></i>
          <span className="font-bold text-sm tracking-wide">{toast.message}</span>
        </div>
      )}
    </div>
  );
};

