import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const NearestLocations: React.FC = () => {
  const [locations, setLocations] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const findLocations = async () => {
    setIsLoading(true);
    setError('');

    // Attempt to get user location
    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const response = await ai.models.generateContent({
          model: "gemini-2.5-flash",
          contents: "Toshkent shahridagi eng yaxshi avtoservislar va Million KM filiallari haqida ma'lumot ber.",
          config: {
            tools: [{ googleMaps: {} }],
            toolConfig: {
              retrievalConfig: {
                latLng: {
                  latitude: position.coords.latitude,
                  longitude: position.coords.longitude
                }
              }
            }
          },
        });

        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
        setLocations(chunks);
      } catch (e) {
        setError("Xarita ma'lumotlarini yuklashda xatolik yuz berdi.");
      } finally {
        setIsLoading(false);
      }
    }, () => {
        setError("Geolokatsiyaga ruxsat berilmadi.");
        setIsLoading(false);
    });
  };

  useEffect(() => {
    findLocations();
  }, []);

  return (
    <div className="max-w-7xl mx-auto px-6 py-20 animate-in fade-in duration-700">
      <div className="text-center mb-16">
        <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-4">Bizning Filiallar</h2>
        <p className="text-slate-500 font-medium">Sizga eng yaqin Million KM servis nuqtasini toping.</p>
      </div>

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-20">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Qidirilmoqda...</p>
        </div>
      ) : error ? (
        <div className="text-center py-20 bg-red-50 rounded-[3rem] border border-red-100 max-w-2xl mx-auto">
          <p className="text-red-600 font-bold mb-4">{error}</p>
          <button onClick={findLocations} className="px-6 py-2 bg-red-600 text-white rounded-xl font-bold text-sm">Qayta urinish</button>
        </div>
      ) : (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
           {/* Static fallback locations if Gemini returns empty for demo */}
           <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 card-shadow">
             <div className="flex justify-between items-start mb-6">
