import React, { useState } from 'react';
import { CAR_DATA } from '../constants';

interface StatusCheckerProps {
  showToast: (msg: string, type: any) => void;
}

const StatusChecker: React.FC<StatusCheckerProps> = ({ showToast }) => {
  const [brand, setBrand] = useState('');
  const [model, setModel] = useState('');
  const [year, setYear] = useState('');
  const [km, setKm] = useState('');
  const [result, setResult] = useState<{ status: 'eligible' | 'not_eligible' | null; message: string }>({ status: null, message: '' });

  const handleCheck = () => {
    if (!brand || !model || !year || !km) {
      showToast("Iltimos, barcha maydonlarni to'ldiring", "error");
      return;
    }

    const currentYear = new Date().getFullYear();
    const carAge = currentYear - parseInt(year);
    const carKm = parseInt(km);
    const limits = CAR_DATA[brand]?.[model];

    if (!limits) {
      setResult({ status: 'not_eligible', message: "Kechirasiz, ushbu model uchun dastur hali ishga tushmagan." });
      return;
    }

    if (carAge <= limits.maxAge && carKm <= limits.maxKm) {
      setResult({ 
        status: 'eligible', 
        message: `Tabriklaymiz! Mashinangiz Million KM dasturiga to'liq mos keladi. Dvigatel ishonchi endi bizning zimmamizda.` 
      });
    } else {
      setResult({ 
        status: 'not_eligible', 
        message: "Limitlar oshib ketgan bo'lsa-da, siz premium bir martalik xizmatimizdan foydalanishingiz mumkin." 
      });
    }
  };

  return (
    <div id="status" className="max-w-4xl mx-auto px-4 py-12 md:py-24">
      <div className="bg-white rounded-[3rem] p-8 md:p-16 border border-gray-100 card-shadow text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-600 to-indigo-600"></div>

        <div className="max-w-2xl mx-auto mb-12">
          <h2 className="text-3xl md:text-5xl font-extrabold mb-4 tracking-tight">Kafolat Statusi</h2>
          <p className="text-gray-500 font-medium">Avtomobilingizni Million KM dasturiga kiritish imkoniyatini tekshiring.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 text-left">
          <div className="space-y-4">
            <div>
              <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Brend</label>
              <select 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-100 font-bold transition-all outline-none appearance-none"
                value={brand}
                onChange={(e) => { setBrand(e.target.value); setModel(''); }}
              >
                <option value="">Tanlang</option>
                {Object.keys(CAR_DATA).map(b => <option key={b} value={b}>{b.toUpperCase()}</option>)}
              </select>
            </div>

            <div>
              <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Model</label>
              <select 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-100 font-bold transition-all outline-none appearance-none disabled:opacity-50"
                disabled={!brand}
                value={model}
                onChange={(e) => setModel(e.target.value)}
              >
                <option value="">Modelni tanlang</option>
                {brand && Object.keys(CAR_DATA[brand]).map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Yili</label>
              <input 
                type="number" 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-100 font-bold transition-all outline-none"
                placeholder="2022"
                value={year}
                onChange={(e) => setYear(e.target.value)}
              />
            </div>
            <div>
              <label className="text-xs font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Yurgan masofa (km)</label>
              <input 
                type="number" 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-100 font-bold transition-all outline-none"
                placeholder="45000"
                value={km}
                onChange={(e) => setKm(e.target.value)}
              />
            </div>
          </div>
        </div>

        <button 
          onClick={handleCheck}
          className="mt-12 px-16 py-5 bg-black text-white rounded-full font-bold text-lg hover:opacity-90 active:scale-95 transition-all shadow-xl shadow-gray-200"
        >
          Tekshirish
        </button>

        {result.status && (
          <div className={`mt-12 p-8 md:p-12 rounded-[2.5rem] animate-fade-up ${result.status === 'eligible' ? 'bg-blue-50/50' : 'bg-red-50/50'}`}>
            <div className="flex flex-col items-center">
              <div className={`w-16 h-16 rounded-full flex items-center justify-center text-white mb-6 ${result.status === 'eligible' ? 'bg-blue-600' : 'bg-red-600'}`}>
                <i className={`fas ${result.status === 'eligible' ? 'fa-check' : 'fa-times'} text-2xl`}></i>
              </div>
