              <p className="text-gray-600 font-medium max-w-md mx-auto mb-8">{result.message}</p>
              <button className={`px-10 py-4 rounded-full font-bold text-sm uppercase tracking-widest text-white shadow-lg transition-all ${result.status === 'eligible' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-red-600 hover:bg-red-700'}`}>
