               <button onClick={() => handleLogin({ uid: 'admin-1', name: 'Admin', email: 'admin@million.km', phone: '+998901234567', gender: 'male', isAdmin: true })} className="w-full bg-[#1d1d1f] text-white py-4.5 rounded-[1.25rem] font-bold hover:bg-black transition-all flex items-center justify-center"><i className="fas fa-user-shield mr-3 text-blue-400"></i> Admin sifatida kirish</button>
