          ) : (
            <button 
              onClick={onLoginClick} 
              className="bg-[#1d1d1f] text-white px-7 py-2.5 rounded-full text-xs font-bold hover:opacity-85 transition-all shadow-xl shadow-gray-200 active:scale-95"
            >
              Kirish
            </button>
          )}
        </div>

        {/* Mobile Hamburger */}
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)} 
          className="md:hidden w-10 h-10 flex items-center justify-center text-[#1d1d1f]"
        >
          <div className="w-5 flex flex-col items-end space-y-1.5">
            <span className={`h-0.5 bg-current transition-all ${isMenuOpen ? 'w-5 rotate-45 translate-y-2' : 'w-5'}`}></span>
            <span className={`h-0.5 bg-current transition-all ${isMenuOpen ? 'opacity-0' : 'w-3'}`}></span>
