              <img 
                src={BRAND_LOGOS[brand]} 
                alt={`${brand} logo`} 
                className="max-h-full max-w-[80%] object-contain grayscale group-hover:grayscale-0 transition-all duration-500" 
              />
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-black capitalize mb-2">{brand}</h3>
              <p className="text-sm text-gray-400 font-medium mb-6">{BRAND_DESCS[brand]}</p>
