  "chevrolet": "https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/Chevrolet-logo.png/640px-Chevrolet-logo.png",
  "kia": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/47/Kia_logo_2021.svg/1024px-Kia_logo_2021.svg.png",
  "liauto": "https://upload.wikimedia.org/wikipedia/commons/thumb/a/a2/Li_Auto_logo.svg/1024px-Li_Auto_logo.svg.png"
};

