import React, { useState, useRef, useEffect } from 'react';
import { CAR_DATA } from '../constants';

interface StatusCheckerProps {
  showToast: (msg: string, type: any) => void;
  onRegister: () => void;
  onOneTime: (brand: string, model: string) => void;
}

const CustomDropdown: React.FC<{
  label: string;
  options: string[];
  value: string;
  onChange: (val: string) => void;
  disabled?: boolean;
  placeholder: string;
}> = ({ label, options, value, onChange, disabled, placeholder }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="relative" ref={dropdownRef}>
      <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">
        {label}
      </label>
      <button
        type="button"
        disabled={disabled}
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full flex items-center justify-between px-6 py-4 rounded-2xl transition-all duration-300 font-bold text-left outline-none ${
          disabled 
            ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
            : 'bg-gray-50 text-slate-900 hover:bg-white hover:ring-2 hover:ring-blue-100 border border-transparent'
        } ${isOpen ? 'bg-white ring-2 ring-blue-500 border-blue-500/10' : ''}`}
      >
        <span className={!value ? 'text-gray-400' : ''}>
          {value ? value.toUpperCase() : placeholder}
        </span>
        <i className={`fas fa-chevron-down text-[10px] transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`}></i>
      </button>

      {isOpen && !disabled && (
        <div className="absolute z-[60] w-full mt-2 bg-white rounded-[1.5rem] shadow-2xl border border-slate-100 overflow-hidden animate-in zoom-in-95 duration-200 origin-top">
          <div className="max-h-60 overflow-y-auto py-2 custom-scrollbar">
            {options.length === 0 ? (
              <div className="px-6 py-4 text-sm text-gray-400 font-medium">Variantlar yo'q</div>
            ) : (
              options.map((opt) => (
                <button
                  key={opt}
                  type="button"
                  onClick={() => {
                    onChange(opt);
                    setIsOpen(false);
                  }}
                  className={`w-full text-left px-6 py-3.5 hover:bg-blue-50 transition-colors font-bold text-sm ${
                    value === opt ? 'text-blue-600 bg-blue-50/50' : 'text-slate-700'
                  }`}
                >
                  {opt.toUpperCase()}
                </button>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

const StatusChecker: React.FC<StatusCheckerProps> = ({ showToast, onRegister, onOneTime }) => {
  const [brand, setBrand] = useState('');
  const [model, setModel] = useState('');
  const [year, setYear] = useState('');
  const [km, setKm] = useState(''); 
  const [displayKm, setDisplayKm] = useState('');
  const [result, setResult] = useState<{ status: 'eligible' | 'not_eligible' | null; message: string }>({ status: null, message: '' });

  const formatWithSpaces = (val: string) => {
    const raw = val.replace(/\D/g, '');
    return raw.replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
  };

  const handleCheck = () => {
    if (!brand || !model || !year || !km) {
      showToast("Iltimos, barcha maydonlarni to'ldiring", "error");
      return;
    }

    const currentYear = new Date().getFullYear();
    const carAge = currentYear - parseInt(year);
    const carKm = parseInt(km);
    const limits = CAR_DATA[brand.toLowerCase()]?.[model];

    if (!limits) {
      setResult({ status: 'not_eligible', message: "Afsuski, ushbu model uchun dastur hali ishga tushmagan." });
      return;
    }

    if (carAge <= limits.maxAge && carKm <= limits.maxKm) {
      setResult({ 
        status: 'eligible', 
        message: `✅ Tabriklaymiz! Mashinangiz Million KM dasturiga to'liq mos keladi.` 
      });
    } else {
      setResult({ 
        status: 'not_eligible', 
        message: "⚠️ Afsuski, limitlar oshib ketgan bo'lsa-da, siz premium bir martalik xizmatimizdan foydalanishingiz mumkin." 
      });
    }
  };

  return (
    <div id="status" className="max-w-4xl mx-auto">
      <div className="bg-white rounded-[3.5rem] p-8 md:p-16 border border-gray-100 shadow-2xl shadow-slate-200/50 text-center relative overflow-hidden">
        {/* Background glow */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-1 bg-gradient-to-r from-transparent via-blue-500 to-transparent opacity-20"></div>

        <div className="mb-14">
          <span className="text-blue-600 font-black uppercase tracking-[0.2em] text-[10px] mb-4 block">Kafolat tekshiruvi</span>
          <h2 className="text-3xl md:text-5xl font-extrabold mb-4 tracking-tight text-slate-900">Mashinangiz statusi</h2>
          <p className="text-gray-400 font-medium max-w-md mx-auto">Million KM dasturiga mos ekanligingizni bir necha soniyada aniqlang</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-left">
          <div className="space-y-6">
            <CustomDropdown 
              label="Brend"
              placeholder="Brendni tanlang"
              options={Object.keys(CAR_DATA)}
              value={brand}
              onChange={(val) => { setBrand(val); setModel(''); }}
            />

            <CustomDropdown 
              label="Model"
              placeholder="Modelni tanlang"
              disabled={!brand}
              options={brand ? Object.keys(CAR_DATA[brand.toLowerCase()]) : []}
              value={model}
              onChange={(val) => setModel(val)}
            />
          </div>

          <div className="space-y-6">
            <div>
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Yili</label>
              <input 
                type="number" 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-900 placeholder:text-gray-300 transition-all border border-transparent focus:border-blue-500/10"
                placeholder="2022"
                value={year}
                onChange={(e) => setYear(e.target.value)}
              />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-4 mb-2 block">Masofa (km)</label>
              <input 
                type="text" 
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-900 placeholder:text-gray-300 transition-all border border-transparent focus:border-blue-500/10"
                placeholder="45 000"
                value={displayKm}
                onChange={(e) => {
                  const raw = e.target.value.replace(/\D/g, '');
                  setKm(raw);
                  setDisplayKm(formatWithSpaces(raw));
                }}
              />
            </div>
          </div>
        </div>

        <div className="mt-14">
          <button 
            onClick={handleCheck}
            className="group relative px-16 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-blue-600 active:scale-95 transition-all shadow-xl shadow-slate-200 overflow-hidden"
          >
            <span className="relative z-10">Statusni tekshirish</span>
            <div className="absolute inset-0 bg-gradient-to-r from-blue-600 to-blue-400 opacity-0 group-hover:opacity-100 transition-opacity"></div>
          </button>
        </div>

        {result.status && (
