            <h3 className={`text-2xl font-extrabold mb-4 tracking-tight ${result.status === 'eligible' ? 'text-blue-900' : 'text-red-900'}`}>
              {result.message}
            </h3>
            <p className="text-gray-500 text-sm font-medium mb-8">
              {result.status === 'eligible' 
                ? "Siz Million KM oilasiga qo'shilish uchun barcha talablarga javob berasiz!" 
                : "Ushbu mashina uchun to'liq kafolat berilmasa ham, bizda ajoyib alternativlar bor."}
