               <button onClick={handleLoginSubmit} className="w-full h-16 bg-black text-white rounded-2xl font-bold text-sm uppercase tracking-widest tap-active shadow-xl shadow-gray-200 mt-4">Continue</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

