import React, { useState, useRef, useEffect } from 'react';
import { CAR_DATA } from '../constants';

interface StatusCheckerProps {
  showToast: (msg: string, type: any) => void;
  onRegister: () => void;
  onOneTime: (brand: string, model: string) => void;
}

const IOSDropdown: React.FC<{
  label: string;
  options: string[];
  value: string;
  onChange: (val: string) => void;
  disabled?: boolean;
  placeholder: string;
}> = ({ label, options, value, onChange, disabled, placeholder }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) setIsOpen(false);
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  return (
    <div className="relative" ref={dropdownRef}>
      <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1 mb-2 block">{label}</label>
      <button
        type="button"
        disabled={disabled}
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full h-16 px-6 rounded-2xl flex items-center justify-between font-bold text-left transition-all tap-active ${disabled ? 'bg-gray-100 text-gray-400' : 'bg-gray-50 text-black hover:bg-white ring-1 ring-gray-100 hover:ring-blue-200'} ${isOpen ? 'ring-2 ring-blue-500 bg-white' : ''}`}
      >
        <span className={!value ? 'text-gray-400' : ''}>{value || placeholder}</span>
        <i className={`fas fa-chevron-down text-[10px] transition-transform ${isOpen ? 'rotate-180' : ''}`}></i>
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-white/80 backdrop-blur-3xl rounded-[24px] shadow-2xl border border-white/20 overflow-hidden animate-spring origin-top">
          <div className="max-h-64 overflow-y-auto py-2 ios-scroll">
            {options.map(opt => (
              <button
                key={opt}
                onClick={() => { onChange(opt); setIsOpen(false); }}
                className={`w-full text-left px-6 py-4 font-bold text-[14px] hover:bg-blue-50 transition-colors ${value === opt ? 'text-blue-600 bg-blue-50/50' : 'text-gray-700'}`}
              >
                {opt.toUpperCase()}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const StatusChecker: React.FC<StatusCheckerProps> = ({ showToast, onRegister, onOneTime }) => {
  const [brand, setBrand] = useState('');
  const [model, setModel] = useState('');
  const [year, setYear] = useState('');
  const [km, setKm] = useState('');
  const [result, setResult] = useState<{ status: 'eligible' | 'not_eligible' | null; message: string }>({ status: null, message: '' });

  const handleCheck = () => {
    if (!brand || !model || !year || !km) {
      showToast("Fields are missing", "error");
      return;
    }
    const limits = CAR_DATA[brand.toLowerCase()]?.[model];
    if (!limits) {
      setResult({ status: 'not_eligible', message: "Model not in program yet." });
      return;
    }
    const currentYear = new Date().getFullYear();
    const carAge = currentYear - parseInt(year);
    const carKm = parseInt(km.replace(/\D/g, ''));

    if (carAge <= limits.maxAge && carKm <= limits.maxKm) {
      setResult({ status: 'eligible', message: "Vehicle Eligible for Million KM Program" });
    } else {
      setResult({ status: 'not_eligible', message: "Standard Limits Exceeded" });
    }
  };

  return (
    <div className="bg-white p-12 md:p-20 squircle border border-gray-100 shadow-xl text-center">
      <div className="mb-16">
        <span className="text-blue-600 font-black uppercase tracking-[0.2em] text-[10px] mb-4 block">Engine Intelligence</span>
        <h2 className="text-4xl md:text-5xl font-extrabold tracking-tight">Check Eligibility</h2>
        <p className="text-gray-400 font-medium mt-4">Discover if your vehicle qualifies for the 1,000,000 KM warranty.</p>
      </div>

      <div className="grid md:grid-cols-2 gap-8 text-left">
        <div className="space-y-6">
          <IOSDropdown label="Make" placeholder="Select Brand" options={Object.keys(CAR_DATA)} value={brand} onChange={v => {setBrand(v); setModel('');}} />
          <IOSDropdown label="Model" placeholder="Select Model" disabled={!brand} options={brand ? Object.keys(CAR_DATA[brand.toLowerCase()]) : []} value={model} onChange={setModel} />
        </div>
        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1 block">Production Year</label>
            <input type="number" placeholder="2022" value={year} onChange={e => setYear(e.target.value)} className="w-full h-16 px-6 rounded-2xl bg-gray-50 font-bold border-none outline-none focus:ring-2 focus:ring-blue-500" />
          </div>
          <div className="space-y-2">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1 block">Mileage (KM)</label>
            <input type="text" placeholder="45 000" value={km} onChange={e => setKm(e.target.value)} className="w-full h-16 px-6 rounded-2xl bg-gray-50 font-bold border-none outline-none focus:ring-2 focus:ring-blue-500" />
          </div>
        </div>
      </div>

      <button onClick={handleCheck} className="mt-16 px-20 py-5 bg-black text-white rounded-[22px] font-bold text-sm uppercase tracking-widest tap-active shadow-2xl shadow-gray-200">
        Run Analysis
      </button>

      {result.status && (
        <div className={`mt-16 p-12 squircle border animate-spring ${result.status === 'eligible' ? 'bg-blue-50/40 border-blue-100' : 'bg-red-50/40 border-red-100'}`}>
          <h3 className={`text-2xl font-extrabold mb-4 tracking-tight ${result.status === 'eligible' ? 'text-blue-900' : 'text-red-900'}`}>{result.message}</h3>
          <p className="text-gray-500 font-medium mb-10">{result.status === 'eligible' ? 'Your vehicle meets all technical requirements for our flagship program.' : 'While standard warranty is unavailable, you can still book premium mobile services.'}</p>
          <button 
            onClick={result.status === 'eligible' ? onRegister : () => onOneTime(brand, model)}
            className={`px-12 py-4 rounded-full font-bold uppercase tracking-widest text-[11px] tap-active ${result.status === 'eligible' ? 'bg-blue-600 text-white' : 'bg-black text-white'}`}
          >
            {result.status === 'eligible' ? 'Activate Warranty' : 'Book Maintenance'}
          </button>
        </div>
      )}
    </div>
  );
};

export default StatusChecker;

import React, { useState, useEffect } from 'react';
import { User } from '../types';

interface NavbarProps {
  currentView: string;
  setView: (view: any) => void;
  user: User | null;
  onLogout: () => void;
  onLoginClick: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentView, setView, user, onLogout, onLoginClick }) => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNav = (view: any, hash: string = '') => {
    setView(view);
    if (hash) {
      setTimeout(() => {
        const el = document.querySelector(hash);
        if (el) window.scrollTo({ top: el.getBoundingClientRect().top + window.scrollY - 100, behavior: 'smooth' });
      }, 100);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <nav className={`fixed top-0 w-full z-[105] transition-all duration-500 ${scrolled ? 'py-4' : 'py-8'}`}>
      <div className={`max-w-[1200px] mx-auto px-6 h-16 flex justify-between items-center transition-all duration-500 ${scrolled ? 'apple-glass squircle mx-6 shadow-[0_10px_40px_rgba(0,0,0,0.05)]' : ''}`}>
        <div className="flex items-center space-x-4 cursor-pointer tap-active" onClick={() => handleNav('home')}>
          <div className="w-11 h-11 bg-black rounded-[12px] flex items-center justify-center shadow-xl shadow-gray-200">
             <span className="text-white font-black text-xl tracking-tighter">1M</span>
          </div>
          <span className="text-xl font-extrabold tracking-tighter text-[#1D1D1F]">Million KM</span>
        </div>

        <div className="hidden md:flex items-center space-x-10">
          <button onClick={() => handleNav('home')} className={`text-[13px] font-bold transition-colors ${currentView === 'home' ? 'text-blue-600' : 'text-gray-400 hover:text-black'}`}>Overview</button>
          <button onClick={() => handleNav('about')} className={`text-[13px] font-bold transition-colors ${currentView === 'about' ? 'text-blue-600' : 'text-gray-400 hover:text-black'}`}>Story</button>
          <button onClick={() => handleNav('home', '#brands')} className="text-[13px] font-bold text-gray-400 hover:text-black">Brands</button>

          <div className="h-5 w-px bg-gray-200/50 mx-2"></div>

          {user ? (
            <div className="flex items-center space-x-5">
              <button onClick={() => handleNav('cabinet')} className="bg-gray-100 text-black h-10 px-5 rounded-full font-bold text-[11px] uppercase tracking-widest tap-active hover:bg-black hover:text-white transition-all">
                {user.name.split(' ')[0]}
              </button>
              <button onClick={onLogout} className="w-10 h-10 rounded-full bg-red-50 text-red-500 tap-active"><i className="fas fa-power-off"></i></button>
            </div>
          ) : (
            <button onClick={onLoginClick} className="bg-black text-white h-10 px-8 rounded-full text-[11px] font-black uppercase tracking-widest tap-active shadow-xl shadow-gray-200">
              Sign In
            </button>
          )}
        </div>

        <button className="md:hidden w-11 h-11 apple-glass rounded-xl flex items-center justify-center text-black tap-active">
          <i className="fas fa-bars"></i>
        </button>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Order } from './types';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import StatusChecker from './components/StatusChecker';
import BrandGrid from './components/BrandGrid';
import Cabinet from './components/Cabinet';
import Admin from './components/Admin';
import MobileService from './components/MobileService';
import AIConsultant from './components/AIConsultant';
import AboutUs from './components/AboutUs';
import NearestLocations from './components/NearestLocations';
import Benefits from './components/Benefits';
import QuickServices from './components/QuickServices';
import { sendTelegramNotification } from './services/telegramService';

type ToastType = 'success' | 'error';
interface ToastState {
  message: string;
  type: ToastType;
  isExiting: boolean;
}

type View = 'home' | 'cabinet' | 'admin' | 'express' | 'fuel' | 'about' | 'locations';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [toast, setToast] = useState<ToastState | null>(null);

  const [loginForm, setLoginForm] = useState({ name: '', phone: '', password: '' });

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    setToast({ message, type, isExiting: false });
    setTimeout(() => setToast(prev => prev ? { ...prev, isExiting: true } : null), 3500);
    setTimeout(() => setToast(null), 4000);
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('million_km_user');
    const savedOrders = localStorage.getItem('million_km_orders');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedOrders) setOrders(JSON.parse(savedOrders));
  }, []);

  const addOrder = async (orderData: Partial<Order>) => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      userName: orderData.userName || currentUser?.name || 'Mehmon',
      brand: orderData.brand || 'Nomaʼlum',
      model: orderData.model || 'Nomaʼlum',
      serviceType: orderData.serviceType || 'Xizmat',
      phone: orderData.phone || currentUser?.phone || '',
      note: orderData.note || '',
      timestamp: new Date().toLocaleString('uz-UZ'),
    };

    const tgMessage = `🚀 <b>Yangi Buyurtma</b>\nMijoz: ${newOrder.userName}\nTel: ${newOrder.phone}\nXizmat: ${newOrder.serviceType}`;
    await sendTelegramNotification(tgMessage);

    const updated = [newOrder, ...orders];
    setOrders(updated);
    localStorage.setItem('million_km_orders', JSON.stringify(updated));
    showToast("Buyurtma qabul qilindi");
  };

  const handleLoginSubmit = () => {
    if (loginForm.name.toLowerCase() === 'admin' && loginForm.password === '123') {
      const adminUser: User = { uid: 'a1', name: 'Admin', email: '', phone: '', gender: '', isAdmin: true };
      setCurrentUser(adminUser);
      localStorage.setItem('million_km_user', JSON.stringify(adminUser));
      setIsAuthModalOpen(false);
      showToast("Xush kelibsiz, Admin");
      return;
    }

    if (!loginForm.name || !loginForm.phone) {
      showToast("Ma'lumotlar to'liq emas", "error");
      return;
    }

    const user: User = { uid: 'u-' + Date.now(), name: loginForm.name, email: '', phone: loginForm.phone, gender: '', isAdmin: false };
    setCurrentUser(user);
    localStorage.setItem('million_km_user', JSON.stringify(user));
    setIsAuthModalOpen(false);
    showToast(`Salom, ${user.name}`);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('million_km_user');
    setCurrentView('home');
    showToast("Tizimdan chiqdingiz");
  };

  const renderView = () => {
    switch (currentView) {
      case 'cabinet': return currentUser ? <Cabinet user={currentUser} showToast={showToast} onOrder={addOrder} /> : <Hero onStart={() => setIsAuthModalOpen(true)} />;
      case 'admin': return currentUser?.isAdmin ? <Admin orders={orders} /> : <div className="p-20 text-center font-bold text-red-500">Ruxsat yo'q</div>;
      case 'express':
      case 'fuel': return <MobileService type={currentView} user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} />;
      case 'about': return <AboutUs />;
      default: return (
        <div className="space-y-32 pb-40">
          <Hero onStart={() => setIsAuthModalOpen(true)} />
          <div id="brands" className="max-w-[1200px] mx-auto px-6"><BrandGrid user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} /></div>
          <div id="benefits" className="max-w-[1200px] mx-auto px-6"><Benefits /></div>
          <div id="status" className="max-w-[900px] mx-auto px-6"><StatusChecker showToast={showToast} onRegister={() => setIsAuthModalOpen(true)} onOneTime={() => setCurrentView('express')} /></div>
          <div id="quick-services-view" className="max-w-[1200px] mx-auto px-6"><QuickServices onSelect={setCurrentView} /></div>
          <div id="locations" className="max-w-[1200px] mx-auto px-6"><NearestLocations /></div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen selection:bg-blue-100 flex flex-col">
      <Navbar currentView={currentView} setView={setCurrentView} user={currentUser} onLogout={handleLogout} onLoginClick={() => setIsAuthModalOpen(true)} />

      <main className="flex-grow">
        {renderView()}
      </main>

      <footer className="py-20 border-t border-gray-100 bg-white/50 backdrop-blur-xl">
        <div className="max-w-7xl mx-auto px-8 flex flex-col md:flex-row justify-between items-center gap-10">
          <div className="text-center md:text-left">
            <h3 className="text-xl font-extrabold tracking-tighter">Million KM</h3>
            <p className="text-sm text-gray-400 mt-2 font-medium italic">Premium avto servis xizmati</p>
          </div>
          <div className="flex space-x-10 text-[13px] font-bold text-gray-500 uppercase tracking-widest">
            <button onClick={() => setCurrentView('home')} className="hover:text-black">Bosh sahifa</button>
            <button onClick={() => setCurrentView('about')} className="hover:text-black">Biz haqimizda</button>
            <a href="tel:+998770200107" className="hover:text-black">Yordam</a>
          </div>
        </div>
      </footer>

      <AIConsultant />

      {toast && (
