  tariffType?: 'one-time' | 'yearly';
  servicesCount?: number;
  totalPrice?: number;
}

import React, { useState, useRef, useEffect } from 'react';
import { CAR_DATA } from '../constants';
import { User, Order } from '../types';

interface BrandGridProps {
  user: User | null;
  onOrder: (order: Partial<Order>) => void;
  onOpenAuth: () => void;
}

const BRAND_LOGOS: Record<string, string> = {
  "chevrolet": "https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/Chevrolet-logo.png/1200px-Chevrolet-logo.png",
  "kia": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/47/Kia_logo.svg/2560px-Kia_logo.svg.png",
  "liauto": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/Li_Auto_logo.png/1200px-Li_Auto_logo.png"
};

const BrandGrid: React.FC<BrandGridProps> = ({ user, onOrder, onOpenAuth }) => {
  const [selectedBrand, setSelectedBrand] = useState<string | null>(null);
  const [selectedModel, setSelectedModel] = useState<string | null>(null);
  const [tariffType, setTariffType] = useState<'one-time' | 'yearly' | null>(null);
  const [yearlyCount, setYearlyCount] = useState(3);

  const modelsRef = useRef<HTMLDivElement>(null);
  const checkoutRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (selectedBrand && modelsRef.current) {
      setTimeout(() => modelsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 300);
    }
  }, [selectedBrand]);

  useEffect(() => {
    if (selectedModel && checkoutRef.current) {
      setTimeout(() => checkoutRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 300);
    }
  }, [selectedModel]);

  const handleModelSelect = (model: string) => {
    setSelectedModel(model);
    setTariffType(null); // Reset choice
  };

  const calculateYearlyPrice = (basePrice: number, count: number) => {
    // Yillik tarif uchun 15% chegirma
    return Math.round((basePrice * count) * 0.85);
  };

  const submitOrder = () => {
    if (!user) return onOpenAuth();
    if (!selectedBrand || !selectedModel || !tariffType) return;

    const basePrice = CAR_DATA[selectedBrand.toLowerCase()][selectedModel].priceOneTime;
    const finalPrice = tariffType === 'one-time' ? basePrice : calculateYearlyPrice(basePrice, yearlyCount);

    onOrder({
      brand: selectedBrand,
      model: selectedModel,
      serviceType: tariffType === 'one-time' ? '1 MARTALIK XIZMAT' : `1 YILLIK TARIF (${yearlyCount} marta)`,
      tariffType,
      servicesCount: tariffType === 'one-time' ? 1 : yearlyCount,
      totalPrice: finalPrice,
      note: `Tanlangan xizmat: ${tariffType === 'one-time' ? 'Bir martalik' : 'Yillik'}. Jami narx: ${finalPrice.toLocaleString()} UZS.`
    });

    setSelectedModel(null);
    setTariffType(null);
  };

  return (
    <div className="py-10">
      <div className="mb-20">
        <h2 className="text-5xl md:text-6xl font-extrabold tracking-tight mb-4">Brendlar</h2>
        <p className="text-xl text-gray-500 font-medium">Faqat eng sara avtomobillar uchun.</p>
      </div>

      <div className="grid md:grid-cols-3 gap-8">
        {Object.keys(CAR_DATA).map((brand) => (
          <div 
            key={brand}
            onClick={() => { setSelectedBrand(brand); setSelectedModel(null); }}
            className={`ios-card bg-white/60 backdrop-blur-xl p-12 squircle border border-white/50 cursor-pointer flex flex-col items-center group ${selectedBrand === brand ? 'ring-4 ring-blue-500/20 shadow-2xl scale-[1.02]' : ''}`}
          >
            <div className="h-28 w-full flex items-center justify-center mb-10 transition-transform duration-500 group-hover:scale-110">
              <img src={BRAND_LOGOS[brand]} alt={brand} className="max-h-full object-contain" />
            </div>
            <h3 className="text-2xl font-extrabold capitalize mb-8">{brand === 'liauto' ? 'Li Auto' : brand}</h3>
            <button className="px-8 py-3 bg-gray-100 text-gray-900 text-[11px] font-bold uppercase tracking-widest rounded-full transition-all group-hover:bg-blue-600 group-hover:text-white">
              Modellarni ko'rish
            </button>
          </div>
        ))}
      </div>

      {selectedBrand && (
        <div ref={modelsRef} className="mt-20 p-12 md:p-20 bg-black squircle text-white animate-spring relative overflow-hidden shadow-2xl">
          <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-blue-500/10 blur-[120px] rounded-full pointer-events-none"></div>

          <div className="flex justify-between items-center mb-20">
            <div>
              <span className="text-blue-400 font-bold uppercase tracking-[0.2em] text-[10px] mb-3 block">Premium Tanlov</span>
              <h3 className="text-4xl md:text-5xl font-extrabold tracking-tight capitalize">{selectedBrand === 'liauto' ? 'Li Auto' : selectedBrand} To'plami</h3>
            </div>
            <button onClick={() => {setSelectedBrand(null); setSelectedModel(null);}} className="w-14 h-14 bg-white/10 rounded-full flex items-center justify-center tap-active hover:bg-white/20 transition-all">
              <i className="fas fa-times"></i>
            </button>
          </div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {Object.entries(CAR_DATA[selectedBrand]).map(([model, info]) => (
              <div 
                key={model} 
                onClick={() => handleModelSelect(model)}
                className={`bg-white/5 p-10 squircle border transition-all ios-card cursor-pointer flex flex-col ${selectedModel === model ? 'border-blue-500 bg-white/10 ring-2 ring-blue-500/20' : 'border-white/10 hover:bg-white/10'}`}
              >
                <div className="flex justify-between items-start mb-8">
                  <h4 className="text-2xl font-extrabold tracking-tight">{model}</h4>
                  <span className="bg-blue-500/20 text-blue-400 text-[10px] font-black px-3 py-1 rounded-lg uppercase tracking-wider">Tanlash</span>
                </div>
                <p className="text-white/40 text-sm font-medium mb-12 italic">"{info.desc}"</p>
                <div className="mt-auto pt-8 border-t border-white/10 flex justify-between items-end">
                  <span className="text-[10px] text-white/30 font-bold uppercase tracking-widest">Bazaviy narx</span>
                  <span className="text-2xl font-black text-blue-400">{info.priceOneTime.toLocaleString()} <span className="text-xs">uzs</span></span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {selectedModel && selectedBrand && (
        <div ref={checkoutRef} className="mt-20 p-12 md:p-20 bg-white squircle border border-gray-100 shadow-2xl animate-spring">
          <div className="text-center mb-20">
            <span className="text-blue-600 font-bold uppercase tracking-[0.2em] text-[10px] mb-4 block">Tarifni tanlang</span>
            <h3 className="text-4xl md:text-5xl font-extrabold tracking-tight text-slate-900">{selectedBrand} {selectedModel} uchun xizmat</h3>
          </div>

          <div className="grid lg:grid-cols-2 gap-12 mb-20">
            {/* One Time Choice */}
            <div 
              onClick={() => setTariffType('one-time')}
              className={`p-10 squircle border-2 transition-all cursor-pointer flex flex-col justify-between ${tariffType === 'one-time' ? 'border-blue-600 bg-blue-50/20' : 'border-gray-100 bg-gray-50/50'}`}
            >
              <div>
                <h4 className="text-2xl font-black mb-4 uppercase tracking-tighter">1 MARTALIK XIZMAT</h4>
                <p className="text-gray-500 mb-8 font-medium">Faqat hozir moy almashtirib olishni xohlaydiganlar uchun.</p>
                <ul className="space-y-3 mb-10">
                   {['Modelga mos moy tanlovi', 'Original filtrlar', 'Dvigatel tekshiruvi', '1 marta bepul avtomoyka'].map(i => (
                     <li key={i} className="flex items-center text-sm font-bold text-gray-700">
                       <i className="fas fa-check text-blue-500 mr-3"></i> {i}
                     </li>
                   ))}
                   <li className="flex items-center text-sm font-bold text-red-400">
                     <i className="fas fa-times mr-3"></i> Million KM kafolati yo'q
                   </li>
                </ul>
              </div>
              <div className="text-3xl font-black text-slate-900">{CAR_DATA[selectedBrand.toLowerCase()][selectedModel].priceOneTime.toLocaleString()} <span className="text-xs">UZS</span></div>
            </div>

            {/* Yearly Choice */}
            <div 
              onClick={() => setTariffType('yearly')}
              className={`p-10 squircle border-2 transition-all cursor-pointer relative overflow-hidden flex flex-col justify-between ${tariffType === 'yearly' ? 'border-blue-600 bg-blue-50/20' : 'border-gray-100 bg-gray-50/50'}`}
            >
              <div className="absolute top-6 right-6 bg-blue-600 text-white text-[10px] font-black px-4 py-2 rounded-full uppercase tracking-widest shadow-lg">Tavsiya etiladi</div>
              <div>
                <h4 className="text-2xl font-black mb-4 uppercase tracking-tighter">1 YILLIK TARIF</h4>
                <p className="text-gray-500 mb-8 font-medium">Mashinasini uzoq muddat sog‘lom saqlamoqchi bo‘lganlar uchun.</p>
                <ul className="space-y-3 mb-10">
                   {['Har safar bepul avtomoyka', 'Doimiy monitoring', 'Maxsus Telegram guruh', '1 000 000 km gacha kafolat'].map(i => (
                     <li key={i} className="flex items-center text-sm font-bold text-gray-700">
                       <i className="fas fa-star text-yellow-500 mr-3"></i> {i}
                     </li>
                   ))}
                </ul>
              </div>
              <div className="text-blue-600 font-black text-sm uppercase tracking-widest mb-2">Eng foydali tanlov</div>
              <div className="text-3xl font-black text-slate-900">Narxni hisoblash <i className="fas fa-arrow-down text-sm ml-2"></i></div>
            </div>
          </div>

          {tariffType === 'yearly' && (
            <div className="bg-slate-900 rounded-[2.5rem] p-12 text-white mb-20 animate-spring">
              <div className="flex flex-col md:flex-row justify-between items-center gap-12">
                <div className="flex-1 text-center md:text-left">
                  <h4 className="text-3xl font-black mb-4 tracking-tight">Yillik xizmatlar soni</h4>
                  <p className="text-white/40 font-medium mb-10">3 tadan 12 tagacha xizmat sonini tanlang. Qancha ko'p bo'lsa, shuncha arzon.</p>

                  <div className="flex flex-wrap justify-center md:justify-start gap-3">
                    {[3,4,5,6,8,10,12].map(num => (
                      <button 
                        key={num}
                        onClick={() => setYearlyCount(num)}
                        className={`w-14 h-14 rounded-2xl font-black text-sm transition-all active:scale-95 ${yearlyCount === num ? 'bg-blue-600 text-white scale-110 shadow-xl' : 'bg-white/10 text-white/60 hover:bg-white/20'}`}
                      >
                        {num}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="w-full md:w-[320px] bg-white/5 backdrop-blur-3xl rounded-[2rem] p-10 border border-white/10 text-center">
                   <div className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-4">Umumiy yillik qiymat</div>
                   <div className="text-4xl font-black mb-4 tracking-tighter">
                     {calculateYearlyPrice(CAR_DATA[selectedBrand.toLowerCase()][selectedModel].priceOneTime, yearlyCount).toLocaleString()}
                   </div>
                   <div className="text-[10px] text-white/40 font-bold uppercase tracking-widest italic line-through mb-1">
                     {(CAR_DATA[selectedBrand.toLowerCase()][selectedModel].priceOneTime * yearlyCount).toLocaleString()} UZS
                   </div>
                   <div className="text-green-400 font-bold text-[11px] uppercase tracking-widest">-15% Chegirma</div>
                </div>
              </div>
            </div>
          )}

          <div className="flex justify-center">
            <button 
              onClick={submitOrder}
              disabled={!tariffType}
              className={`px-24 py-6 rounded-[22px] font-black uppercase tracking-[0.2em] text-sm transition-all shadow-2xl active:scale-95 disabled:opacity-30 ${tariffType === 'yearly' ? 'bg-blue-600 text-white' : 'bg-black text-white'}`}
            >
              {tariffType === 'yearly' ? 'Yillik tarifni sotib olish' : 'Xizmatni band qilish'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default BrandGrid;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Order } from './types';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import StatusChecker from './components/StatusChecker';
import BrandGrid from './components/BrandGrid';
import Cabinet from './components/Cabinet';
import Admin from './components/Admin';
import MobileService from './components/MobileService';
import AIConsultant from './components/AIConsultant';
import AboutUs from './components/AboutUs';
import NearestLocations from './components/NearestLocations';
import Benefits from './components/Benefits';
import QuickServices from './components/QuickServices';
import { sendTelegramNotification } from './services/telegramService';

type ToastType = 'success' | 'error';
interface ToastState {
  message: string;
  type: ToastType;
  isExiting: boolean;
}

type View = 'home' | 'cabinet' | 'admin' | 'express' | 'fuel' | 'about' | 'locations';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [toast, setToast] = useState<ToastState | null>(null);

  const [loginForm, setLoginForm] = useState({ name: '', phone: '', password: '' });

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    setToast({ message, type, isExiting: false });
    setTimeout(() => setToast(prev => prev ? { ...prev, isExiting: true } : null), 3500);
    setTimeout(() => setToast(null), 4000);
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('million_km_user');
    const savedOrders = localStorage.getItem('million_km_orders');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedOrders) setOrders(JSON.parse(savedOrders));
  }, []);

  const addOrder = async (orderData: Partial<Order>) => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      userName: orderData.userName || currentUser?.name || 'Mehmon',
      brand: orderData.brand || 'Nomaʼlum',
      model: orderData.model || 'Nomaʼlum',
      serviceType: orderData.serviceType || 'Xizmat',
      phone: orderData.phone || currentUser?.phone || '',
      note: orderData.note || '',
      timestamp: new Date().toLocaleString('uz-UZ'),
      tariffType: orderData.tariffType,
      servicesCount: orderData.servicesCount,
      totalPrice: orderData.totalPrice
    };

    let tgMessage = `🚀 <b>Yangi Buyurtma</b>\n`;
    tgMessage += `👤 Mijoz: ${newOrder.userName}\n`;
    tgMessage += `📞 Tel: ${newOrder.phone}\n`;
    tgMessage += `🚗 Transport: ${newOrder.brand} ${newOrder.model}\n`;
    tgMessage += `🛠 Xizmat turi: ${newOrder.serviceType}\n`;
    if (newOrder.totalPrice) {
      tgMessage += `💰 Jami narx: ${newOrder.totalPrice.toLocaleString()} UZS\n`;
    }
    if (newOrder.note) {
      tgMessage += `📝 Izoh: ${newOrder.note}`;
    }

    await sendTelegramNotification(tgMessage);

    const updated = [newOrder, ...orders];
    setOrders(updated);
    localStorage.setItem('million_km_orders', JSON.stringify(updated));
    showToast("Buyurtma qabul qilindi");
  };

  const handleLoginSubmit = () => {
    if (loginForm.name.toLowerCase() === 'admin' && loginForm.password === '123') {
      const adminUser: User = { uid: 'a1', name: 'Admin', email: '', phone: '', gender: '', isAdmin: true };
      setCurrentUser(adminUser);
      localStorage.setItem('million_km_user', JSON.stringify(adminUser));
      setIsAuthModalOpen(false);
      showToast("Xush kelibsiz, Admin");
      return;
    }

    if (!loginForm.name || !loginForm.phone) {
      showToast("Ma'lumotlar to'liq emas", "error");
      return;
    }

    const user: User = { uid: 'u-' + Date.now(), name: loginForm.name, email: '', phone: loginForm.phone, gender: '', isAdmin: false };
    setCurrentUser(user);
    localStorage.setItem('million_km_user', JSON.stringify(user));
    setIsAuthModalOpen(false);
    showToast(`Salom, ${user.name}`);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('million_km_user');
    setCurrentView('home');
    showToast("Tizimdan chiqdingiz");
  };

  const renderView = () => {
    switch (currentView) {
      case 'cabinet': return currentUser ? <Cabinet user={currentUser} showToast={showToast} onOrder={addOrder} /> : <Hero onStart={() => setIsAuthModalOpen(true)} />;
      case 'admin': return currentUser?.isAdmin ? <Admin orders={orders} /> : <div className="p-20 text-center font-bold text-red-500">Ruxsat yo'q</div>;
      case 'express':
      case 'fuel': return <MobileService type={currentView} user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} />;
      case 'about': return <AboutUs />;
      default: return (
        <div className="space-y-32 pb-40">
          <Hero onStart={() => setIsAuthModalOpen(true)} />
          <div id="brands" className="max-w-[1200px] mx-auto px-6"><BrandGrid user={currentUser} onOrder={addOrder} onOpenAuth={() => setIsAuthModalOpen(true)} /></div>
          <div id="benefits" className="max-w-[1200px] mx-auto px-6"><Benefits /></div>
          <div id="status" className="max-w-[900px] mx-auto px-6"><StatusChecker showToast={showToast} onRegister={() => setIsAuthModalOpen(true)} onOneTime={() => setCurrentView('express')} /></div>
          <div id="quick-services-view" className="max-w-[1200px] mx-auto px-6"><QuickServices onSelect={setCurrentView} /></div>
          <div id="locations" className="max-w-[1200px] mx-auto px-6"><NearestLocations /></div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen selection:bg-blue-100 flex flex-col">
      <Navbar currentView={currentView} setView={setCurrentView} user={currentUser} onLogout={handleLogout} onLoginClick={() => setIsAuthModalOpen(true)} />

      <main className="flex-grow">
        {renderView()}
      </main>

      <footer className="py-20 border-t border-gray-100 bg-white/50 backdrop-blur-xl">
        <div className="max-w-7xl mx-auto px-8 flex flex-col md:flex-row justify-between items-center gap-10">
          <div className="text-center md:text-left">
            <h3 className="text-xl font-extrabold tracking-tighter">Million KM</h3>
            <p className="text-sm text-gray-400 mt-2 font-medium italic">Premium avto servis xizmati</p>
          </div>
          <div className="flex space-x-10 text-[13px] font-bold text-gray-500 uppercase tracking-widest">
            <button onClick={() => setCurrentView('home')} className="hover:text-black">Bosh sahifa</button>
            <button onClick={() => setCurrentView('about')} className="hover:text-black">Biz haqimizda</button>
            <a href="tel:+998770200107" className="hover:text-black">Yordam</a>
          </div>
        </div>
      </footer>

      <AIConsultant />

      {toast && (
        <div className={`fixed top-0 left-1/2 -translate-x-1/2 z-[300] w-full max-w-[420px] px-6 pointer-events-none ${toast.isExiting ? 'animate-dynamic-exit opacity-0' : 'animate-dynamic-island'}`}>
          <div className={`mt-4 p-5 rounded-[2.5rem] shadow-[0_25px_60px_-10px_rgba(0,0,0,0.2)] flex items-center space-x-5 border backdrop-blur-3xl transition-all duration-700 ${toast.type === 'success' ? 'bg-[#1C1C1E] text-white border-white/10' : 'bg-[#FF3B30] text-white border-white/20'}`}>
            <div className={`w-12 h-12 rounded-full flex items-center justify-center flex-shrink-0 ${toast.type === 'success' ? 'bg-blue-50/50 shadow-lg shadow-blue-500/20' : 'bg-white/20'}`}>
              <i className={`fas ${toast.type === 'success' ? 'fa-check' : 'fa-exclamation-triangle'} text-lg`}></i>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 leading-none mb-1.5">
                {toast.type === 'success' ? 'Tizim xabari' : 'Diqqat qiling'}
              </span>
              <span className="font-bold text-[15px] tracking-tight">{toast.message}</span>
            </div>
          </div>
        </div>
      )}

      {isAuthModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-black/40 backdrop-blur-md animate-in">
          <div className="bg-white/90 backdrop-blur-3xl squircle p-10 w-full max-w-md shadow-2xl relative border border-white/50 animate-spring">
            <button onClick={() => setIsAuthModalOpen(false)} className="absolute top-10 right-10 text-gray-400 hover:text-black transition-colors tap-active"><i className="fas fa-times text-xl"></i></button>
            <h2 className="text-3xl font-extrabold tracking-tight mb-10">Kirish</h2>
            <div className="space-y-6">
               <div className="space-y-2">
                 <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1">Shaxsingiz</label>
                 <input type="text" value={loginForm.name} onChange={e => setLoginForm({...loginForm, name: e.target.value})} placeholder="To'liq ismingiz" className="w-full h-16 px-6 rounded-2xl bg-gray-100/50 border-none outline-none focus:ring-2 focus:ring-blue-500 font-bold" />
               </div>
               {loginForm.name.toLowerCase() !== 'admin' ? (
                  <div className="space-y-2">
                    <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1">Bog'lanish</label>
                    <input type="tel" value={loginForm.phone} onChange={e => setLoginForm({...loginForm, phone: e.target.value})} placeholder="+998" className="w-full h-16 px-6 rounded-2xl bg-gray-100/50 border-none outline-none focus:ring-2 focus:ring-blue-500 font-bold" />
                  </div>
               ) : (
                  <div className="space-y-2">
                    <label className="text-[11px] font-bold text-gray-400 uppercase tracking-widest ml-1">Pin kod</label>
                    <input type="password" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} placeholder="••••" className="w-full h-16 px-6 rounded-2xl bg-gray-100/50 border-none outline-none focus:ring-2 focus:ring-blue-500 font-bold text-center tracking-[0.5em]" />
                  </div>
               )}
               <button onClick={handleLoginSubmit} className="w-full h-16 bg-black text-white rounded-2xl font-bold text-sm uppercase tracking-widest tap-active shadow-xl shadow-gray-200 mt-4">Davom etish</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { CAR_DATA } from '../constants';
import { User, Order } from '../types';

interface BrandGridProps {
  user: User | null;
  onOrder: (order: Partial<Order>) => void;
  onOpenAuth: () => void;
}

const BRAND_LOGOS: Record<string, string> = {
  "chevrolet": "https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/Chevrolet-logo.png/1200px-Chevrolet-logo.png",
  "kia": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/47/Kia_logo.svg/2560px-Kia_logo.svg.png",
  "liauto": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/Li_Auto_logo.png/1200px-Li_Auto_logo.png"
};

const BrandGrid: React.FC<BrandGridProps> = ({ user, onOrder, onOpenAuth }) => {
  const [selectedBrand, setSelectedBrand] = useState<string | null>(null);
  const [selectedModel, setSelectedModel] = useState<string | null>(null);
  const [tariffType, setTariffType] = useState<'one-time' | 'yearly' | null>(null);
  const [yearlyCount, setYearlyCount] = useState(3);

